SET FOREIGN_KEY_CHECKS = 0;
SET NAMES utf8mb4;
-- announcement DDL
CREATE TABLE `announcement` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
`title` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL Comment "公告标题",
`content` TEXT CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL Comment "公告内容",
`type` TINYINT UNSIGNED NOT NULL DEFAULT 1 Comment "公告类型：1系统 2活动 3更新",
`status` TINYINT UNSIGNED NOT NULL DEFAULT 1 Comment "状态：1正常 0禁用",
`sort` INT NOT NULL DEFAULT 0 Comment "排序，数字越大越靠前",
`cover` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' Comment "封面图URL",
`created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
`updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0),
`deleted_at` DATETIME NULL,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 11 ROW_FORMAT = Dynamic COMMENT = "公告表";
-- classification DDL
CREATE TABLE `classification` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
`name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`url` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`updated_at` DATETIME(3) NOT NULL,
`created_at` DATETIME(3) NOT NULL,
`icon` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`gradient` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`count` INT UNSIGNED NOT NULL DEFAULT 0,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 15 ROW_FORMAT = Dynamic;
-- mp_user DDL
CREATE TABLE `mp_user` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
`name` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`openid` VARCHAR(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '',
`created_at` DATETIME NOT NULL,
`deleted_at` DATETIME NULL,
`unionid` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '',
`session_key` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '',
`avatar_url` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL Comment "用户头像",
`updated_at` DATETIME NOT NULL,
`phone` VARCHAR(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '',
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 6 ROW_FORMAT = Dynamic;
-- user_collect DDL
CREATE TABLE `user_collect` (`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
`user_id` BIGINT UNSIGNED NOT NULL Comment "用户ID",
`wallpaper_id` BIGINT UNSIGNED NOT NULL Comment "壁纸ID",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "收藏时间",
INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
UNIQUE INDEX `idx_user_wallpaper`(`user_id` ASC,`wallpaper_id` ASC) USING BTREE,
INDEX `idx_wallpaper_id`(`wallpaper_id` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 5 ROW_FORMAT = Dynamic COMMENT = "用户收藏记录";
-- user_download DDL
CREATE TABLE `user_download` (`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
`user_id` BIGINT UNSIGNED NOT NULL Comment "用户ID",
`wallpaper_id` BIGINT UNSIGNED NOT NULL Comment "壁纸ID",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "下载时间",
UNIQUE INDEX `uk_user_wallpaper`(`user_id` ASC,`wallpaper_id` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 4 ROW_FORMAT = Dynamic COMMENT = "用户下载记录";
-- user_like DDL
CREATE TABLE `user_like` (`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
`user_id` BIGINT UNSIGNED NOT NULL Comment "用户ID",
`wallpaper_id` BIGINT UNSIGNED NOT NULL Comment "壁纸ID",
`created_at` DATETIME NULL DEFAULT CURRENT_TIMESTAMP Comment "点赞时间",
INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
UNIQUE INDEX `idx_user_wallpaper`(`user_id` ASC,`wallpaper_id` ASC) USING BTREE,
INDEX `idx_wallpaper_id`(`wallpaper_id` ASC) USING BTREE,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 22 ROW_FORMAT = Dynamic COMMENT = "用户点赞记录";
-- wallpaper DDL
CREATE TABLE `wallpaper` (`id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
`title` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`url` VARCHAR(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`created_at` DATETIME NOT NULL,
`md5` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
`like_count` INT UNSIGNED NOT NULL DEFAULT 0 Comment "点赞数",
`download_count` INT UNSIGNED NOT NULL DEFAULT 0 Comment "下载数",
`collect_count` INT UNSIGNED NOT NULL DEFAULT 0 Comment "收藏数",
`view_count` INT UNSIGNED NOT NULL DEFAULT 0 Comment "浏览量",
`updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
`classify_id` INT NOT NULL,
`deleted_at` DATETIME NULL,
PRIMARY KEY (`id`)) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci AUTO_INCREMENT = 3635 ROW_FORMAT = Dynamic;
-- announcement DML
INSERT INTO `announcement` (`id`,`title`,`content`,`type`,`status`,`sort`,`cover`,`created_at`,`updated_at`,`deleted_at`) VALUES (1,'系统维护通知','尊敬的用户，系统将于2025-12-20 00:00-02:00进行例行维护，期间部分功能可能暂时无法使用，请合理安排操作时间。',1,1,100,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(2,'用户协议更新','平台用户服务协议已更新，主要优化隐私政策与服务条款，用户继续使用即表示同意最新协议内容。',1,1,95,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(3,'账号安全提醒','为保障您的账号安全，请定期修改密码，不要向他人泄露验证码，平台不会以任何理由索要密码。',1,1,90,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(4,'双十二狂欢活动开启','年度双十二特惠活动正式上线，全场商品低至5折，叠加优惠券更划算，活动时间12.10-12.15。',2,1,85,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(5,'新用户注册送好礼','新用户完成注册即可领取新人礼包，包含无门槛优惠券、积分等福利，仅限首次注册用户。',2,1,80,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(6,'限时秒杀活动预告','每日10点、15点、20点开启限时秒杀，爆款商品低价抢购，先到先得，售完即止。',2,1,75,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(7,'会员专属福利活动','平台会员可享受专属折扣、优先发货、专属客服等权益，开通会员立享多重福利。',2,0,70,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(8,'APP V2.5.0版本更新','本次更新优化页面加载速度，修复已知BUG，新增消息推送功能，建议立即更新体验。',3,1,65,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(9,'后台管理系统升级','管理后台新增数据统计、权限管理优化、操作日志记录等功能，提升管理效率。',3,1,60,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL),(10,'接口服务优化更新','系统接口全面优化，响应速度提升50%，稳定性增强，为用户提供更流畅的服务体验。',3,0,55,'system/2aa37b73-4186-4140-88ad-b11d687f33a8.png','2026-05-17 07:44:13','2026-05-17 08:17:31',NULL);
